begin;

alter table "Chapter"
  add column if not exists "parentChapterId" text;

alter table "ConceptNode"
  add column if not exists "lessonFlow" jsonb,
  add column if not exists "lessonMedia" jsonb,
  add column if not exists "lessonType" text not null default 'flow',
  add column if not exists "contentReady" boolean not null default false,
  add column if not exists "lessonStatus" text not null default 'draft';

create index if not exists "Chapter_parentChapterId_idx" on "Chapter"("parentChapterId");
create index if not exists "Chapter_courseId_orderIndex_idx" on "Chapter"("courseId", "orderIndex");
create index if not exists "ConceptNode_chapterId_orderIndex_idx" on "ConceptNode"("chapterId", "orderIndex");

insert into storage.buckets (id, name, public)
values
  ('lesson-assets', 'lesson-assets', true),
  ('lesson-videos', 'lesson-videos', true)
on conflict (id) do update set public = excluded.public;

do $$
declare
  student_id text := 'default-user-id';
  course_id text := gen_random_uuid()::text;
  ch1 text := gen_random_uuid()::text;
  ch2 text := gen_random_uuid()::text;
  ch3 text := gen_random_uuid()::text;
  ch1_s1 text := gen_random_uuid()::text;
  ch1_s2 text := gen_random_uuid()::text;
  ch2_s1 text := gen_random_uuid()::text;
  ch2_s2 text := gen_random_uuid()::text;
  ch2_s3 text := gen_random_uuid()::text;
  ch3_s1 text := gen_random_uuid()::text;
  ch3_s2 text := gen_random_uuid()::text;
  ch3_s3 text := gen_random_uuid()::text;
  draft_flow jsonb := $json$[
    {"id":"draft-note","type":"markdown","title":"Bài học đang biên soạn","config":{"content":"Nội dung tương tác của bài này chưa được seed. Bài sẽ hiển thị khóa nội dung cho đến khi được publish."},"completionRule":{"type":"viewed"}}
  ]$json$::jsonb;
  origin_flow jsonb := $json$[{"id":"origin-intro","type":"component_group","title":"Cỗ Máy Thời Gian","linkedMediaId":"origin-opening-video","navigation_config":{"shortLabel":"Khởi hành"},"config":{"layout":"vertical","revealMode":"sequential","completionMode":"all","components":[{"id":"origin-intro-dialogue","type":"dialogue","title":"Cỗ Máy Thời Gian","linkedMediaId":"origin-opening-video","config":{"title":"Cỗ Máy Thời Gian","subtitle":"Thế kỷ VIII – VI trước Công nguyên","characters":{"guide":{"name":"Sophia","role":"Người dẫn truyện","avatar":"guide","color":"from-indigo-500 to-violet-600"},"elder":{"name":"Già làng Kael","role":"Trưởng bộ tộc","avatar":"elder","color":"from-amber-500 to-orange-600"},"skeptic":{"name":"Lyra","role":"Người hoài nghi trẻ","avatar":"skeptic","color":"from-cyan-500 to-blue-600"},"slave":{"name":"Borin","role":"Người lao động chân tay","avatar":"slave","color":"from-stone-500 to-stone-700"},"noble":{"name":"Theon","role":"Quý tộc / trí thức","avatar":"noble","color":"from-fuchsia-500 to-purple-600"}},"lines":[{"id":"dialog_01","who":"guide","text":"Nhiệm vụ của bạn: đi tìm một thứ 'vũ khí tư duy' hoàn toàn mới — có tên là TRIẾT HỌC. Nhưng để tìm thấy nó, ta phải vượt qua 2 thử thách, đại diện cho 2 NGUỒN GỐC khai sinh ra triết học."}]},"completionRule":{"type":"viewed"}},{"id":"origin-journey-choice","type":"mcq","title":"Lựa chọn điểm khởi hành","linkedMediaId":"origin-opening-video","config":{"question":"Bạn muốn bắt đầu hành trình từ đâu?","options":[{"id":"athens","text":"Quảng trường Athena (Hy Lạp)","isCorrect":true},{"id":"ganges","text":"Bên bờ sông Hằng (Ấn Độ)","isCorrect":true},{"id":"yellowriver","text":"Lưu vực Hoàng Hà (Trung Hoa)","isCorrect":true}],"explanation":"Tuyệt vời! Dù khởi hành từ đâu, mọi nền văn minh cổ đại đều cùng chạm tới một bước ngoặt tư duy giống nhau. Lên đường thôi!","startPoints":[{"id":"athens","label":"Quảng trường Athena","place":"Hy Lạp","icon":"account_balance"},{"id":"ganges","label":"Bên bờ sông Hằng","place":"Ấn Độ","icon":"water"},{"id":"yellowriver","label":"Lưu vực Hoàng Hà","place":"Trung Hoa","icon":"temple_buddhist"}],"startConfirm":"Tuyệt vời! Dù khởi hành từ đâu, mọi nền văn minh cổ đại đều cùng chạm tới một bước ngoặt tư duy giống nhau. Lên đường thôi!"},"completionRule":{"type":"correct"}}]},"completionRule":{"type":"all"}},{"id":"cognitive-scene","type":"dialogue","title":"Giải mã sấm truyền","linkedMediaId":"cognitive-video","config":{"badge":"Thử thách 1 / 2","subtitle":"Nguồn gốc nhận thức","pieceLabel":"NGUỒN GỐC NHẬN THỨC","characters":{"guide":{"name":"Sophia","role":"Người dẫn truyện","avatar":"guide","color":"from-indigo-500 to-violet-600"},"elder":{"name":"Già làng Kael","role":"Trưởng bộ tộc","avatar":"elder","color":"from-amber-500 to-orange-600"},"skeptic":{"name":"Lyra","role":"Người hoài nghi trẻ","avatar":"skeptic","color":"from-cyan-500 to-blue-600"},"slave":{"name":"Borin","role":"Người lao động chân tay","avatar":"slave","color":"from-stone-500 to-stone-700"},"noble":{"name":"Theon","role":"Quý tộc / trí thức","avatar":"noble","color":"from-fuchsia-500 to-purple-600"}},"lines":[{"who":"elder","text":"Tai họa này từ đâu mà ra?! Hỡi người trẻ kia, hãy giải thích cho cả bộ tộc!"}]},"completionRule":{"type":"viewed"}},{"id":"cognitive-myth-quiz","type":"mcq","title":"Tư duy huyền thoại","linkedMediaId":"cognitive-video","config":{"question":"Con người thời cổ đại thường dùng cách nào để giải thích về các hiện tượng tự nhiên lớn (như mưa giông, sấm chớp, động đất)?","options":[{"text":"Cho rằng đó là sự giận dữ hoặc ý chí của các vị thần linh siêu nhiên.","isCorrect":true},{"text":"Dựa vào các quy luật khoa học và sự vận động của Trái Đất để chứng minh.","isCorrect":false},{"text":"Xem đó là những hiện tượng ngẫu nhiên, không có nguyên nhân hay ý nghĩa gì.","isCorrect":false}],"correctFeedback":"Chính xác! Khi chưa có tri thức khoa học, con người cổ đại giải thích mọi hiện tượng tự nhiên bằng THẦN THOẠI và TÍN NGƯỠNG — coi đó là ý chí hay cơn thịnh nộ của thần linh. Đây chính là hình thức 'triết lý' sơ khai đầu tiên của loài người.","wrongFeedback":"Chưa đúng. Hãy nhớ bối cảnh: thời cổ đại CHƯA có khoa học để chứng minh, và con người luôn khao khát tìm nguyên nhân chứ không xem mọi việc là ngẫu nhiên vô nghĩa. Họ giải thích tự nhiên bằng niềm tin vào thần linh siêu nhiên.","explanation":"Chính xác! Khi chưa có tri thức khoa học, con người cổ đại giải thích mọi hiện tượng tự nhiên bằng THẦN THOẠI và TÍN NGƯỠNG — coi đó là ý chí hay cơn thịnh nộ của thần linh. Đây chính là hình thức 'triết lý' sơ khai đầu tiên của loài người."},"completionRule":{"type":"correct"}},{"id":"cognitive-turning-point","type":"component_group","title":"Bước ngoặt hoài nghi","linkedMediaId":"cognitive-video","navigation_config":{"shortLabel":"Hoài nghi"},"config":{"layout":"vertical","revealMode":"sequential","completionMode":"all","components":[{"id":"lyra-doubt","type":"dialogue","title":"Bước ngoặt hoài nghi","linkedMediaId":"cognitive-video","config":{"characters":{"guide":{"name":"Sophia","role":"Người dẫn truyện","avatar":"guide","color":"from-indigo-500 to-violet-600"},"elder":{"name":"Già làng Kael","role":"Trưởng bộ tộc","avatar":"elder","color":"from-amber-500 to-orange-600"},"skeptic":{"name":"Lyra","role":"Người hoài nghi trẻ","avatar":"skeptic","color":"from-cyan-500 to-blue-600"},"slave":{"name":"Borin","role":"Người lao động chân tay","avatar":"slave","color":"from-stone-500 to-stone-700"},"noble":{"name":"Theon","role":"Quý tộc / trí thức","avatar":"noble","color":"from-fuchsia-500 to-purple-600"}},"lines":[{"who":"skeptic","text":"Trời ơi, sao số phận chúng ta khổ thế này! Mưa giông, lũ lụt, hạn hán rồi động đất... năm nào cũng ập tới. Chúng ta đã quỳ lạy, đã tế bao nhiêu lễ vật cho thần linh, vậy mà thiên tai VẪN cứ giáng xuống, chẳng gì đổi thay. Lẽ nào chúng ta mãi mãi bất lực, hay có điều gì khác mà chúng ta chưa biết về thiên nhiên, chẳng hề phụ thuộc vào tâm trạng của các vị thần?"}]},"completionRule":{"type":"viewed"}},{"id":"cognitive-shift-quiz","type":"mcq","title":"Nhận thức","linkedMediaId":"cognitive-video","config":{"question":"Câu hỏi của Lyra hé lộ điều gì đang BẮT ĐẦU thay đổi trong cách con người suy nghĩ?","options":[{"text":"Con người bắt đầu đi tìm quy luật, lý lẽ để giải thích thế giới — thay cho thần thánh.","isCorrect":true},{"text":"Con người quyết định tế lễ nhiều hơn nữa cho chắc chắn.","isCorrect":false},{"text":"Con người từ bỏ hoàn toàn việc tìm hiểu thế giới.","isCorrect":false}],"correctFeedback":"Chính xác! Khoảnh khắc con người ngờ vực thần thoại và đi tìm QUY LUẬT bằng lý lẽ — đó là lúc tư duy lý luận, tức TRIẾT HỌC, bắt đầu nảy mầm.","wrongFeedback":"Chưa đúng. Hãy để ý: Lyra không kêu gọi tế lễ — cô ấy đang đi tìm một 'quy luật tự nhiên'. Đó mới là mầm mống của tư duy mới.","explanation":"Chính xác! Khoảnh khắc con người ngờ vực thần thoại và đi tìm QUY LUẬT bằng lý lẽ — đó là lúc tư duy lý luận, tức TRIẾT HỌC, bắt đầu nảy mầm."},"completionRule":{"type":"correct"}}]},"completionRule":{"type":"all"}},{"id":"cognitive-piece","type":"knowledge_piece","title":"Đúc kết: Nguồn gốc nhận thức của triết học","linkedMediaId":"cognitive-video","config":{"pieceId":"cognitive","label":"NGUỒN GỐC NHẬN THỨC","shortLabel":"Nhận thức","icon":"psychology","color":"from-cyan-400 via-blue-500 to-primary-700","summary":"Triết học là hình thức tư duy lý luận đầu tiên thay thế tư duy huyền thoại.","steps":[{"icon":"psychology","head":"1. Nhu cầu tự nhiên","body":"Nhận thức, hiểu biết thế giới xung quanh là nhu cầu tự nhiên của con người để sinh tồn."},{"icon":"auto_stories","head":"2. Tư duy huyền thoại","body":"Thần thoại và tín ngưỡng nguyên thủy là loại hình triết lý ĐẦU TIÊN dùng để giải thích thế giới."},{"icon":"hub","head":"3. Phát triển tư duy trừu tượng","body":"Khi nhận thức lớn lên, con người biết trừu tượng hóa, khái quát hóa các tri thức riêng lẻ thành cái chung."},{"icon":"emoji_objects","head":"4. Triết học ra đời","body":"Triết học là hình thức tư duy lý luận đầu tiên THAY THẾ tư duy huyền thoại — giải thích thế giới bằng khái niệm, phạm trù, quy luật phổ quát."}],"takeaways":["1. Nhu cầu tự nhiên: Nhận thức, hiểu biết thế giới xung quanh là nhu cầu tự nhiên của con người để sinh tồn.","2. Tư duy huyền thoại: Thần thoại và tín ngưỡng nguyên thủy là loại hình triết lý ĐẦU TIÊN dùng để giải thích thế giới.","3. Phát triển tư duy trừu tượng: Khi nhận thức lớn lên, con người biết trừu tượng hóa, khái quát hóa các tri thức riêng lẻ thành cái chung.","4. Triết học ra đời: Triết học là hình thức tư duy lý luận đầu tiên THAY THẾ tư duy huyền thoại — giải thích thế giới bằng khái niệm, phạm trù, quy luật phổ quát."],"reward":"Bạn đã thu thập được mảnh ghép: NGUỒN GỐC NHẬN THỨC!"},"completionRule":{"type":"viewed"}},{"id":"social-role-experience","type":"component_group","title":"...khi phương thức sản xuất thay đổi...","linkedMediaId":"social-video","navigation_config":{"shortLabel":"Xã hội"},"config":{"layout":"vertical","revealMode":"sequential","completionMode":"all","components":[{"id":"social-setup","type":"dialogue","title":"...khi phương thức sản xuất thay đổi...","linkedMediaId":"social-video","config":{"badge":"Thử thách 2 / 2","subtitle":"Nguồn gốc xã hội","pieceLabel":"NGUỒN GỐC XÃ HỘI","characters":{"guide":{"name":"Sophia","role":"Người dẫn truyện","avatar":"guide","color":"from-indigo-500 to-violet-600"},"elder":{"name":"Già làng Kael","role":"Trưởng bộ tộc","avatar":"elder","color":"from-amber-500 to-orange-600"},"skeptic":{"name":"Lyra","role":"Người hoài nghi trẻ","avatar":"skeptic","color":"from-cyan-500 to-blue-600"},"slave":{"name":"Borin","role":"Người lao động chân tay","avatar":"slave","color":"from-stone-500 to-stone-700"},"noble":{"name":"Theon","role":"Quý tộc / trí thức","avatar":"noble","color":"from-fuchsia-500 to-purple-600"}},"lines":[{"who":"guide","text":"Nhiều thế hệ trôi qua, khi phương thức sản xuất thay đổi — con người biết rèn đồng, rèn sắt, của cải bắt đầu dư thừa — xã hội phân chia thành Chủ nô và Nô lệ."},{"who":"guide","text":"Để hiểu ai mới đủ điều kiện làm triết học, hãy thử sống MỘT NGÀY trong hai vai khác nhau nhé."}]},"completionRule":{"type":"viewed"}},{"id":"social-borin-dialogue","type":"dialogue","title":"Một ngày của Borin","linkedMediaId":"social-video","config":{"characters":{"guide":{"name":"Sophia","role":"Người dẫn truyện","avatar":"guide","color":"from-indigo-500 to-violet-600"},"elder":{"name":"Già làng Kael","role":"Trưởng bộ tộc","avatar":"elder","color":"from-amber-500 to-orange-600"},"skeptic":{"name":"Lyra","role":"Người hoài nghi trẻ","avatar":"skeptic","color":"from-cyan-500 to-blue-600"},"slave":{"name":"Borin","role":"Người lao động chân tay","avatar":"slave","color":"from-stone-500 to-stone-700"},"noble":{"name":"Theon","role":"Quý tộc / trí thức","avatar":"noble","color":"from-fuchsia-500 to-purple-600"}},"lines":[{"who":"slave","text":"Trời chưa sáng, tôi đã phải ra đồng cày cuốc, rồi vác đá xây tháp tới kiệt sức. Cuối ngày, điều tôi nghĩ đến chỉ là ăn vội một bữa và ngủ để mai còn tiếp tục lao động."}]},"completionRule":{"type":"viewed"}},{"id":"social-role-slave","type":"mcq","title":"Vai 1: Người lao động chân tay","linkedMediaId":"social-video","config":{"roleWho":"slave","intro":"Trời chưa sáng, Borin đã phải ra đồng cày cuốc, vác đá xây tháp tới kiệt sức.","question":"Cuối ngày, kiệt quệ vì lo từng bữa ăn — bạn có thời gian và sức lực để ngồi suy ngẫm về nguồn gốc vũ trụ không?","options":[{"text":"Không. Mình chỉ kịp ăn vội rồi ngủ để mai lại lao động.","isCorrect":true},{"text":"Có. Mình thức trắng đêm để viết một học thuyết triết học.","isCorrect":false}],"correctFeedback":"Đúng vậy. Lao động chân tay nặng nhọc và nỗi lo sinh tồn không để lại điều kiện nào cho việc nghiên cứu lý luận.","wrongFeedback":"Khó lắm! Một người kiệt sức vì lao động chân tay và lo miếng ăn gần như không còn thời gian, sức lực cho tư duy lý luận.","explanation":"Đúng vậy. Lao động chân tay nặng nhọc và nỗi lo sinh tồn không để lại điều kiện nào cho việc nghiên cứu lý luận."},"completionRule":{"type":"correct"}}]},"completionRule":{"type":"all"}},{"id":"social-theon-experience","type":"component_group","title":"Vai 2: Tầng lớp quý tộc / trí thức","linkedMediaId":"social-video","navigation_config":{"shortLabel":"Vai 2"},"config":{"layout":"vertical","revealMode":"sequential","completionMode":"all","components":[{"id":"social-theon-dialogue","type":"dialogue","title":"Một buổi chiều của Theon","linkedMediaId":"social-video","config":{"characters":{"guide":{"name":"Sophia","role":"Người dẫn truyện","avatar":"guide","color":"from-indigo-500 to-violet-600"},"elder":{"name":"Già làng Kael","role":"Trưởng bộ tộc","avatar":"elder","color":"from-amber-500 to-orange-600"},"skeptic":{"name":"Lyra","role":"Người hoài nghi trẻ","avatar":"skeptic","color":"from-cyan-500 to-blue-600"},"slave":{"name":"Borin","role":"Người lao động chân tay","avatar":"slave","color":"from-stone-500 to-stone-700"},"noble":{"name":"Theon","role":"Quý tộc / trí thức","avatar":"noble","color":"from-fuchsia-500 to-purple-600"}},"lines":[{"who":"noble","text":"Ta có của cải dư thừa và không phải lao động chân tay. Khi chiều xuống, ta có thể ngắm sao trời, đàm đạo cùng bạn hữu và suy nghĩ xem thế giới này vận hành theo quy luật nào."}]},"completionRule":{"type":"viewed"}},{"id":"social-role-noble","type":"mcq","title":"Vai 2: Tầng lớp quý tộc / trí thức","linkedMediaId":"social-video","config":{"roleWho":"noble","intro":"Theon có của cải dư thừa, không phải lao động chân tay. Chiều đến, ông thong dong ngắm sao trời và đàm đạo cùng bạn hữu.","question":"Với điều kiện sống như vậy, Theon có thể làm gì?","options":[{"text":"Dành thời gian quan sát, suy ngẫm và hệ thống hóa tri thức thành học thuyết.","isCorrect":true},{"text":"Cũng chẳng làm được gì vì quá bận đi cày.","isCorrect":false}],"correctFeedback":"Chính xác. Có của cải dư thừa và thời gian rảnh, tầng lớp trí óc mới đủ điều kiện để nghiên cứu và sáng tạo lý luận.","wrongFeedback":"Không phải. Theon KHÔNG phải lao động chân tay — ông có dư thời gian để suy ngẫm, đó là điểm mấu chốt.","explanation":"Chính xác. Có của cải dư thừa và thời gian rảnh, tầng lớp trí óc mới đủ điều kiện để nghiên cứu và sáng tạo lý luận."},"completionRule":{"type":"correct"}}]},"completionRule":{"type":"all"}},{"id":"social-core-quiz","type":"mcq","title":"Câu hỏi then chốt","linkedMediaId":"social-video","config":{"question":"Tại đại hội bộ tộc, câu hỏi lớn được đặt ra: NHÓM NÀO đủ điều kiện, thời gian và nhu cầu để hệ thống hóa tri thức thành học thuyết và trở thành các 'Nhà thông thái'?","options":[{"text":"Tầng lớp lao động trí óc (quý tộc, trí thức).","isCorrect":true},{"text":"Tầng lớp lao động chân tay (nô lệ).","isCorrect":false},{"text":"Cả hai nhóm đều như nhau.","isCorrect":false}],"correctFeedback":"Hoàn toàn đúng! Chỉ khi lao động trí óc TÁCH KHỎI lao động chân tay, tầng lớp trí thức mới xuất hiện và có điều kiện hệ thống hóa tri thức thành triết học.","wrongFeedback":"Hãy nhớ lại trải nghiệm vừa rồi: chỉ tầng lớp có của cải dư thừa và thời gian rảnh (lao động trí óc) mới đủ điều kiện làm việc đó.","explanation":"Hoàn toàn đúng! Chỉ khi lao động trí óc TÁCH KHỎI lao động chân tay, tầng lớp trí thức mới xuất hiện và có điều kiện hệ thống hóa tri thức thành triết học."},"completionRule":{"type":"correct"}},{"id":"social-warning","type":"markdown","title":"Điều kiện xã hội","linkedMediaId":"social-video","config":{"content":"- Triết học KHÔNG THỂ ra đời trong một xã hội mông muội, dã man. Nó chỉ ra đời khi xã hội đạt đến một trình độ tương đối cao của sản xuất xã hội, phân công lao động xã hội hình thành, giai cấp phân hóa rõ và mạnh, nhà nước ra đời.\n- Tầng lớp tri thức xuất hiện đóng vai trò quan trọng trong việc hệ thống hóa toàn bộ tri thức của thời đại để xây dựng nên các học thuyết, lý luận, triết thuyết.\n- Triết học, ngay từ khi xuất hiện đã mang trong mình tính giai cấp sâu sắc.","warning":["Triết học KHÔNG THỂ ra đời trong một xã hội mông muội, dã man. Nó chỉ ra đời khi xã hội đạt đến một trình độ tương đối cao của sản xuất xã hội, phân công lao động xã hội hình thành, giai cấp phân hóa rõ và mạnh, nhà nước ra đời.","Tầng lớp tri thức xuất hiện đóng vai trò quan trọng trong việc hệ thống hóa toàn bộ tri thức của thời đại để xây dựng nên các học thuyết, lý luận, triết thuyết.","Triết học, ngay từ khi xuất hiện đã mang trong mình tính giai cấp sâu sắc."]},"completionRule":{"type":"viewed"}},{"id":"social-origin-chain","type":"chain_sorting","title":"Lắp ráp chuỗi nhân quả: Vì sao triết học ra đời?","linkedMediaId":"social-video","config":{"instruction":"Chọn các mắt xích theo ĐÚNG thứ tự nhân quả, từ gốc tới ngọn.","items":[{"id":"c1","order":0,"icon":"agriculture","text":"Sản xuất phát triển, chế độ tư hữu hình thành, của cải dư thừa."},{"id":"c2","order":1,"icon":"groups","text":"Xã hội phân chia giai cấp (chế độ chiếm hữu nô lệ)."},{"id":"c3","order":2,"icon":"engineering","text":"Lao động trí óc tách khỏi lao động chân tay."},{"id":"c4","order":3,"icon":"school","text":"Tầng lớp trí thức xuất hiện và hệ thống hóa tri thức thành triết học."}],"successFeedback":"Chuỗi nhân quả đã sáng lên! Đây chính là NGUỒN GỐC XÃ HỘI của triết học.","reward":"NGUỒN GỐC XÃ HỘI"},"completionRule":{"type":"correct"}},{"id":"social-piece","type":"knowledge_piece","title":"Đúc kết nguồn gốc xã hội","linkedMediaId":"social-video","config":{"pieceId":"social","label":"NGUỒN GỐC XÃ HỘI","shortLabel":"Xã hội","icon":"groups","color":"from-fuchsia-400 via-purple-500 to-primary-700","summary":"Chuỗi nhân quả đã sáng lên! Đây chính là NGUỒN GỐC XÃ HỘI của triết học.","takeaways":["Triết học KHÔNG THỂ ra đời trong một xã hội mông muội, dã man. Nó chỉ ra đời khi xã hội đạt đến một trình độ tương đối cao của sản xuất xã hội, phân công lao động xã hội hình thành, giai cấp phân hóa rõ và mạnh, nhà nước ra đời.","Tầng lớp tri thức xuất hiện đóng vai trò quan trọng trong việc hệ thống hóa toàn bộ tri thức của thời đại để xây dựng nên các học thuyết, lý luận, triết thuyết.","Triết học, ngay từ khi xuất hiện đã mang trong mình tính giai cấp sâu sắc."],"reward":"Bạn đã thu thập được mảnh ghép: NGUỒN GỐC XÃ HỘI!"},"completionRule":{"type":"viewed"}},{"id":"origin-union","type":"mindmap_reveal","title":"Hợp nhất tri thức","config":{"center":"TRIẾT HỌC RA ĐỜI","centerNote":"Thế kỷ VIII – VI TCN, ở cả phương Đông và phương Tây","finalStatement":"Triết học ra đời từ sự HỢP NHẤT của hai nguồn gốc: NHU CẦU NHẬN THỨC thế giới của con người và những ĐIỀU KIỆN XÃ HỘI chín muồi — phân công lao động, giai cấp, và sự xuất hiện của tầng lớp trí thức.","guideLines":["Chúc mừng nhà du hành! Bạn đã ghép xong bức tranh hoàn chỉnh.","Triết học không từ trên trời rơi xuống. Nó nảy sinh từ chính NHU CẦU HIỂU BIẾT của con người (nguồn gốc nhận thức)...","...và từ những ĐIỀU KIỆN XÃ HỘI chín muồi: phân công lao động, giai cấp, tầng lớp trí thức (nguồn gốc xã hội)."],"nodes":[{"id":"cognitive","label":"Nguồn gốc nhận thức","detail":"Nhu cầu hiểu biết thế giới → tư duy lý luận thay thế huyền thoại.","points":["Nhu cầu tự nhiên: hiểu biết thế giới.","Tư duy huyền thoại → tư duy trừu tượng, khái quát.","Triết học = tư duy lý luận đầu tiên thay thế huyền thoại."],"icon":"psychology","color":"from-cyan-600 to-blue-700"},{"id":"social","label":"Nguồn gốc xã hội","detail":"Điều kiện xã hội chín muồi → tầng lớp trí thức ra đời.","points":["Sản xuất phát triển, tư hữu & giai cấp xuất hiện.","Lao động trí óc tách khỏi lao động chân tay.","Tầng lớp trí thức hệ thống hóa tri thức thành học thuyết."],"icon":"groups","color":"from-fuchsia-600 to-purple-700"}]},"completionRule":{"type":"viewed"}},{"id":"origin-final-quiz","type":"quiz_sequence","title":"Kiểm tra cuối bài","config":{"questions":[{"question":"Triết học ra đời vào khoảng thời gian nào?","options":["Thế kỷ XV – XVI sau CN","Thế kỷ VIII – VI trước CN","Thế kỷ I sau CN","Thời kỳ đồ đá cũ"],"correctIndex":1,"explanation":"Triết học ra đời khoảng thế kỷ VIII – VI trước Công nguyên, ở cả phương Đông và phương Tây, tại các trung tâm văn minh lớn."},{"question":"Triết học có mấy nguồn gốc cơ bản?","options":["Một: nguồn gốc thần thánh","Hai: nhận thức và xã hội","Ba: kinh tế, chính trị, văn hóa","Không có nguồn gốc xác định"],"correctIndex":1,"explanation":"Triết học có hai nguồn gốc: nguồn gốc nhận thức (nhu cầu hiểu biết, vượt qua tư duy huyền thoại) và nguồn gốc xã hội (phân công lao động, giai cấp, tầng lớp trí thức)."},{"question":"Về nguồn gốc nhận thức, triết học là hình thức tư duy thay thế cho cái gì?","options":["Thay thế khoa học tự nhiên","Thay thế tư duy huyền thoại và tôn giáo","Thay thế lao động chân tay","Thay thế nghệ thuật"],"correctIndex":1,"explanation":"Triết học là hình thức tư duy lý luận đầu tiên thay thế cho tư duy huyền thoại và tôn giáo, giải thích thế giới bằng khái niệm, phạm trù, quy luật phổ quát."},{"question":"Điều kiện xã hội nào là tiền đề cho triết học ra đời?","options":["Xã hội mông muội, chưa phân hóa","Phân công lao động, giai cấp xuất hiện, lao động trí óc tách khỏi chân tay","Mọi người đều làm nông nghiệp như nhau","Xã hội không có của cải dư thừa"],"correctIndex":1,"explanation":"Triết học ra đời khi sản xuất phát triển, tư hữu và giai cấp xuất hiện, lao động trí óc tách khỏi lao động chân tay, hình thành tầng lớp trí thức có điều kiện hệ thống hóa tri thức."},{"question":"Vì sao tầng lớp trí thức (lao động trí óc) lại là người sáng tạo ra triết học?","options":["Vì họ khỏe mạnh hơn","Vì họ có của cải dư thừa, thời gian và nhu cầu để nghiên cứu, hệ thống hóa tri thức","Vì họ được thần linh ban cho","Vì họ làm nhiều việc chân tay hơn"],"correctIndex":1,"explanation":"Nhờ có của cải dư thừa và không phải lao động chân tay, tầng lớp trí thức có điều kiện và nhu cầu nghiên cứu, đủ năng lực hệ thống hóa các quan niệm thành học thuyết, lý luận."}]},"completionRule":{"type":"correct"}},{"id":"origin-final","type":"final_summary","title":"Nhà Khai Sáng","config":{"badgeNote":"Chương 1.1 — Nguồn gốc của triết học","message":"Bạn đã hoàn thành Hành trình Khai Sáng và nắm được trọn vẹn hai nguồn gốc của triết học. Tri thức là ngọn đuốc — hãy tiếp tục thắp sáng!","keyTakeaways":["Nhu cầu tự nhiên: hiểu biết thế giới.","Tư duy huyền thoại → tư duy trừu tượng, khái quát.","Triết học = tư duy lý luận đầu tiên thay thế huyền thoại.","Sản xuất phát triển, tư hữu & giai cấp xuất hiện.","Lao động trí óc tách khỏi lao động chân tay.","Tầng lớp trí thức hệ thống hóa tri thức thành học thuyết."],"rewards":{"xp":120,"badge":"Nhà Khai Sáng"},"quote":{"text":"Các nhà triết học đã chỉ giải thích thế giới bằng nhiều cách khác nhau, song vấn đề là cải tạo thế giới.","author":"Karl Marx, Luận cương về Feuerbach"},"actions":{"retryButton":true,"nextLessonButton":true}},"completionRule":{"type":"viewed"}}]$json$::jsonb;
  concept_flow jsonb := $json$[{"id":"concept-origin-group","type":"component_group","title":"Quan niệm Triết học","navigation_config":{"shortLabel":"Quan niệm"},"config":{"layout":"vertical","revealMode":"sequential","completionMode":"all","components":[{"id":"concept-opening","type":"markdown","title":"Quan niệm Triết học","config":{"content":"Triết học là một hoạt động tinh thần bậc cao, xuất hiện khi con người biết nhìn thế giới bằng lý tính, kinh nghiệm và khái quát hóa. Hãy đặt các cách hiểu tiêu biểu vào đúng không gian văn minh để thấy chiều sâu của khái niệm Triết học."},"completionRule":{"type":"viewed"}},{"id":"ancient-origin-map","type":"map_target_matching","title":"Quan niệm Triết học","config":{"targets":[{"id":"china","label":"Trung Quốc","icon":"temple_buddhist","detail":"Triết biểu hiện cao của trí tuệ, là sự hiểu biết sâu sắc về thế giới thiên - địa - nhân và định hướng nhân sinh quan.","x":72,"y":44},{"id":"india","label":"Ấn Độ","icon":"water","detail":"Dar'sana chỉ sự chiêm ngưỡng bằng lý trí, là con đường suy ngẫm dẫn con người đến với lẽ phải.","x":58,"y":58},{"id":"greece","label":"Hy Lạp","icon":"account_balance","detail":"Philosophia là yêu mến sự thông thái, nhấn mạnh khát vọng tìm kiếm chân lý.","x":32,"y":44}],"items":[{"id":"zhe","text":"哲","targetId":"china"},{"id":"darsana","text":"Dar'sana","targetId":"india"},{"id":"philosophia","text":"φιλοσοφία","targetId":"greece"}],"summary":"Cả ở phương Đông và phương Tây, ngay từ đầu, triết học đã là hoạt động tinh thần bậc cao, là loại hình nhận thức có trình độ trừu tượng hóa và khái quát hóa rất cao. Triết học nhìn nhận và đánh giá đối tượng thông qua thực tế và thông qua hiện tượng quan sát được về con người và vũ trụ, tồn tại với tư cách là một hình thái ý thức xã hội."},"completionRule":{"type":"correct"}}]},"completionRule":{"type":"all"}},{"id":"worldview-sorting-group","type":"component_group","title":"Triết học khác thần thoại - tôn giáo như thế nào?","navigation_config":{"shortLabel":"Phân loại"},"config":{"layout":"vertical","revealMode":"sequential","completionMode":"all","components":[{"id":"worldview-sorting-intro","type":"markdown","title":"Triết học khác gì với thần thoại - tôn giáo?","config":{"content":"Triết học và các hình thức nhận thức khác đều muốn vẽ nên bức tranh về thế giới, nhưng công cụ của chúng rất khác nhau. Hãy phân loại các yếu tố dưới đây để làm rõ tính đặc thù của nhận thức triết học."},"completionRule":{"type":"viewed"}},{"id":"worldview-sorting","type":"category_sorting","title":"Phân loại thế giới quan","config":{"categories":[{"id":"myth-religion","label":"Thần thoại - Tôn giáo","description":"Thế giới quan dựa trên niềm tin, tưởng tượng và sức mạnh siêu nhiên."},{"id":"philosophy","label":"Triết học","description":"Nhận thức dựa trên lý tính, logic, kinh nghiệm và quy luật."}],"cards":[{"id":"faith","text":"Niềm tin","categoryId":"myth-religion"},{"id":"imagined-world","text":"Quan niệm tưởng tượng về thế giới","categoryId":"myth-religion"},{"id":"personification","text":"Nhân cách hóa tự nhiên","categoryId":"myth-religion"},{"id":"rituals","text":"Các nghi lễ","categoryId":"myth-religion"},{"id":"reason","text":"Công cụ lý tính","categoryId":"philosophy"},{"id":"logic","text":"Các tiêu chuẩn logic","categoryId":"philosophy"},{"id":"experience","text":"Kinh nghiệm con người khám phá thực tại","categoryId":"philosophy"},{"id":"laws","text":"Các quy luật","categoryId":"philosophy"}],"summary":"Triết học lý giải thế giới bằng lý tính, logic và khái quát hóa thay vì chỉ dựa vào niềm tin hoặc tưởng tượng."},"completionRule":{"type":"correct"}}]},"completionRule":{"type":"all"}},{"id":"definition-citations","type":"knowledge_piece","title":"Định nghĩa kinh điển","config":{"pieceId":"classic-definitions","label":"Định nghĩa kinh điển","icon":"format_quote","summary":"Bách khoa thư Britannica định nghĩa: “Triết học là sự xem xét lý tính, trừu tượng và có phương pháp về thực tại với tính cách là một chỉnh thể hoặc những khía cạnh nền tảng của kinh nghiệm và sự tồn tại nguời. Sự truy vấn triết học (Philosophical Inquiry) là thành phần trung tâm của lịch sử trí tuệ của nhiều nền văn minh\n”Bách khoa thư triết học mới của Viện Triết học Nga xuất bản năm 2001 đưa ra định nghĩa: Triết học là hình thức đặc biệt của nhận thức và ý thức xã hội về thế giới, được thể hiện thành hệ thống tri thức về những nguyên tắc cơ bản và nền tảng của tồn tại ngƣời, về những đặc trưng bản chất nhất của mối quan hệ giữa con ngừời với tự nhiên, với xã hội và với đời sống tinh thần."},"completionRule":{"type":"viewed"}},{"id":"marxist-leninist-definition-piece","type":"knowledge_piece","title":"Định nghĩa triết học Mác - Lênin","config":{"pieceId":"marxist-leninist-definition","label":"Định nghĩa triết học Mác - Lênin","icon":"school","summary":"Với sự ra đời của triết học Mác - Lênin, triết học là hệ thống quan điểm lý luận chung nhất về thế giới và vị trí con người trong thế giới đó, là khoa học về những quy luật vận động, phát triển chung nhất của tự nhiên, xã hội và tư duy."},"completionRule":{"type":"viewed"}},{"id":"definition-core-mindmap","type":"mindmap_reveal","title":"Nội dung chủ yếu của các định nghĩa triết học","config":{"center":"Nội dung chủ yếu của các định nghĩa Triết học","layoutConfig":{"type":"matrix"},"nodes":[{"id":"social-consciousness","back":"Triết học là một hình thái ý thức xã hội."},{"id":"world-object","back":"Khách thể khám phá của triết học là thế giới trong hệ thống chỉnh thể toàn vẹn vốn có của nó."},{"id":"universal-laws","back":"Triết học giải thích sự vật, hiện tượng, quá trình và quan hệ của thế giới nhằm tìm ra những quy luật phổ biến nhất chi phối thế giới, con người và tư duy."},{"id":"systematic-abstract","back":"Tri thức triết học mang tính hệ thống, logic và trừu tượng về thế giới, bao gồm những nguyên tắc cơ bản và quan điểm nền tảng về mọi tồn tại."},{"id":"worldview-core","back":"Triết học là hạt nhân của thế giới quan."}],"summary":"Triết học là hình thái đặc biệt của ý thức xã hội, được thể hiện thành hệ thống các quan điểm lý luận chung nhất về thế giới, về con người và về tư duy của con người trong thế giới ấy. Đặc biệt, triết học chính là hạt nhân của thế giới quan."},"completionRule":{"type":"viewed"}},{"id":"concept-final","type":"final_summary","title":"Hoàn thành bài Khái niệm triết học","config":{"message":"Bạn đã hoàn thiện nội dung cốt lõi của khái niệm triết học.","keyTakeaways":["Triết học là hoạt động tinh thần bậc cao, có trình độ trừu tượng hóa và khái quát hóa cao.","Triết học khác thần thoại - tôn giáo ở công cụ lý tính, logic và việc tìm kiếm quy luật.","Triết học là hình thái đặc biệt của ý thức xã hội và là hạt nhân của thế giới quan."],"rewards":{"xp":100,"badge":"Người nắm khái niệm"},"actions":{"retryButton":true,"nextLessonButton":true}},"completionRule":{"type":"viewed"}}]$json$::jsonb;
  concept_media jsonb := $json$[{"id":"concept-map-image","type":"image","url":"https://vqkliqnanzemrjifvawf.supabase.co/storage/v1/object/public/lesson-assets/chapter-1/1.1.b/1.b.media.png","title":"Khái niệm Triết học","description":"Triết học đã xuất hiện như một tất yếu khách quan ở cả phương Đông và phương Tây gần như cùng một thời điểm (khoảng thế kỷ VIII – VI trước Công nguyên).","alt":"Bản đồ minh hoạ khái niệm triết học ở Trung Quốc, Ấn Độ và Hy Lạp"}]$json$::jsonb;
  worldview_core_flow jsonb := $json$[{"id":"worldview-core-intro","type":"markdown","title":"Triết học là hạt nhân của thế giới quan","config":{"content":"Triết học là hạt nhân của thế giới quan và có sự phát triển nhảy vọt với sự ra đời của triết học Mác - Lênin. Hãy bắt đầu bằng việc lựa chọn định nghĩa chính xác nhất."},"completionRule":{"type":"viewed"}},{"id":"marxist-leninist-definition","type":"mcq","title":"Định nghĩa triết học Mác - Lênin","config":{"question":"Đâu là định nghĩa chính xác nhất về triết học Mác - Lênin?","options":[{"id":"belief-only","text":"Triết học chỉ là những quan niệm tưởng tượng và niềm tin thuần túy của con người về vị trí của mình trong thế giới.","isCorrect":false},{"id":"general-laws","text":"Với sự ra đời của triết học Mác - Lênin, triết học là hệ thống quan điểm lý luận chung nhất về thế giới và vị trí con người trong thế giới đó, là khoa học về những quy luật vận động, phát triển chung nhất của tự nhiên, xã hội và tư duy.","isCorrect":true},{"id":"specific-natural-science","text":"Triết học là một ngành khoa học cụ thể chỉ nghiên cứu về các hiện tượng tự nhiên tách rời khỏi xã hội và tư duy.","isCorrect":false}],"correctFeedback":"Đúng. Triết học Mác - Lênin thể hiện rõ vai trò hạt nhân thế giới quan bằng lý luận khoa học về các quy luật chung nhất của tự nhiên, xã hội và tư duy.","wrongFeedback":"Chưa chính xác. Hãy chú ý phạm vi khái quát của triết học Mác - Lênin: thế giới, con người, tự nhiên, xã hội và tư duy."},"completionRule":{"type":"correct"}},{"id":"philosophy-specificity","type":"matching_columns","title":"Tính đặc thù của triết học","config":{"instruction":"Nối nội dung ở cột trái với mô tả phù hợp ở cột phải.","leftColumn":[{"id":"philosophical-knowledge","text":"Tri thức khoa học triết học"},{"id":"method","text":"Phương pháp nghiên cứu của triết học"},{"id":"theoretical-worldview","text":"Cơ sở để diễn tả thế giới quan bằng lý luận"}],"rightColumn":[{"id":"abstract-general","text":"Mang tính khái quát cao dựa trên sự trừu tượng hóa sâu sắc về thế giới, về bản chất cuộc sống con người."},{"id":"whole-world","text":"Xem xét thế giới như một chỉnh thể trong mối quan hệ giữa các yếu tố và tìm cách đưa ra một hệ thống các quan niệm về chỉnh thể đó."},{"id":"history-summary","text":"Dựa trên cơ sở tổng kết toàn bộ lịch sử của khoa học và lịch sử của bản thân tư tưởng triết học."}],"correctPairs":[{"leftId":"philosophical-knowledge","rightId":"abstract-general"},{"leftId":"method","rightId":"whole-world"},{"leftId":"theoretical-worldview","rightId":"history-summary"}],"summary":"Nhận thức triết học không đi vào từng ngóc ngách cô lập mà xem xét thế giới như một chỉnh thể toàn vẹn."},"completionRule":{"type":"correct"}},{"id":"not-all-philosophy-science","type":"true_false","title":"Mọi học thuyết triết học đều là khoa học?","config":{"statement":"Mọi học thuyết triết học đều là khoa học.","correctAnswer":false,"explanation":"Không phải mọi triết học đều là khoa học. Song các học thuyết triết học đều có đóng góp nhất định cho sự hình thành tri thức khoa học triết học trong lịch sử."},"completionRule":{"type":"correct"}},{"id":"philosophy-spiral-piece","type":"progression_spiral","title":"Đường xoáy ốc của lịch sử tư tưởng","config":{"center":"Lịch sử tư tưởng triết học","instruction":"Mở từng mốc để thấy vì sao triết học phát triển như những vòng khâu nối tiếp trong lịch sử tư tưởng.","milestones":[{"id":"not-every-philosophy-science","label":"Không phải mọi triết học đều là khoa học","icon":"help","summary":"Các học thuyết triết học không tự động có tính khoa học chỉ vì chúng được gọi là triết học.","detail":"Tính khoa học phụ thuộc vào đối tượng, hệ thống tri thức và phương pháp nghiên cứu của từng học thuyết."},{"id":"historical-contribution","label":"Vòng khâu lịch sử","icon":"all_inclusive","summary":"Mỗi học thuyết triết học đều là một vòng khâu trong đường xoáy ốc của lịch sử tư tưởng nhân loại.","detail":"Ngay cả những học thuyết còn hạn chế vẫn có đóng góp nhất định cho sự hình thành tri thức triết học về sau."},{"id":"scientific-level","label":"Trình độ khoa học","icon":"science","summary":"Trình độ khoa học của triết học phụ thuộc vào sự phát triển của đối tượng nghiên cứu, hệ tri thức và phương pháp.","detail":"Vì vậy cần đánh giá triết học trong điều kiện lịch sử cụ thể, không tách khỏi trình độ nhận thức của thời đại."},{"id":"worldview-core","label":"Hạt nhân thế giới quan","icon":"psychology","summary":"Triết học là hình thái đặc biệt của ý thức xã hội và giữ vai trò hạt nhân lý luận của thế giới quan.","detail":"Với triết học Mác - Lênin, vai trò này được thể hiện thành hệ thống quan điểm khoa học về các quy luật chung nhất của tự nhiên, xã hội và tư duy."}],"summary":"Triết học phát triển qua các vòng khâu lịch sử; triết học Mác - Lênin là bước phát triển khoa học trong vai trò hạt nhân lý luận của thế giới quan."},"completionRule":{"type":"viewed"}},{"id":"worldview-core-final","type":"final_summary","title":"Hoàn thành bài Triết học - hạt nhân lý luận của thế giới quan","config":{"message":"Bạn đã nắm được vì sao triết học giữ vai trò hạt nhân lý luận của thế giới quan.","keyTakeaways":["Triết học Mác - Lênin là hệ thống quan điểm lý luận chung nhất về thế giới và vị trí con người trong thế giới.","Triết học nghiên cứu những quy luật vận động, phát triển chung nhất của tự nhiên, xã hội và tư duy.","Triết học khác khoa học cụ thể ở mức độ khái quát, phương pháp xem xét chỉnh thể và nền tảng tổng kết lịch sử khoa học - tư tưởng.","Không phải mọi học thuyết triết học đều là khoa học, nhưng chúng đều góp phần vào lịch sử tư tưởng triết học."],"rewards":{"xp":100,"badge":"Người nắm hạt nhân thế giới quan"},"actions":{"retryButton":true,"nextLessonButton":true}},"completionRule":{"type":"viewed"}}]$json$::jsonb;
